            <div class="max-h-[68vh] overflow-y-auto px-5 py-6 sm:px-7">@if($errors->any())<div class="mb-5 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-800">Revise os dados informados.</div>@endif<div class="mb-6 flex items-center gap-4 rounded-2xl bg-slate-50 p-4"><div class="grid size-16 shrink-0 place-items-center overflow-hidden rounded-full bg-brand-100 text-lg font-black text-brand-700"><img x-show="preview && !removed" :src="preview" class="size-full object-cover"><span x-show="!preview || removed" x-text="initials()"></span></div><div><label class="btn-secondary cursor-pointer">Escolher foto<input type="file" name="avatar" accept="image/png,image/jpeg,image/webp" class="hidden" @change="chooseImage($event)"></label><button x-show="form.has_avatar" type="button" class="ml-2 text-sm font-semibold text-red-600" @click="removed=!removed" x-text="removed?'Manter foto':'Remover'"></button><input type="hidden" name="remove_avatar" :value="removed?1:0"><p class="mt-2 text-xs text-slate-400">JPG, PNG ou WebP, até 2 MB.</p></div></div><div class="grid gap-5 sm:grid-cols-2"><div class="sm:col-span-2"><label class="label">Nome completo</label><input class="field" name="name" x-model="form.name" required x-ref="nameInput"></div><div><label class="label">E-mail</label><input class="field" type="email" name="email" x-model="form.email" required></div><div><label class="label">Telefone</label><input class="field" name="phone" x-model="form.phone"></div><div><label class="label">Perfil de acesso</label><select class="field" name="role" x-model="form.role" :disabled="form.self"><option value="member">Aluno</option><option value="trainer">Professor</option><option value="admin">Administrador</option></select></div><div><label class="label">Status</label><select class="field" name="active" x-model="form.active" :disabled="form.self"><option value="1">Ativo</option><option value="0">Inativo</option></select></div><div><label class="label">Data de nascimento</label><input class="field" type="date" name="birth_date" x-model="form.birth_date"></div><div><label class="label">Senha <span x-show="mode==='edit'" class="font-normal text-slate-400">(opcional)</span></label><input class="field" type="password" name="password" :required="mode==='create'"></div><div><label class="label">Confirmar senha</label><input class="field" type="password" name="password_confirmation" :required="mode==='create'"></div><div class="sm:col-span-2"><label class="label">Endereço</label><input class="field" name="address" x-model="form.address"></div></div><p x-show="form.self" class="mt-4 text-xs text-slate-400">Seu próprio acesso administrativo é protegido.</p></div>
            <div class="flex flex-col-reverse gap-3 border-t border-slate-100 px-5 py-4 sm:flex-row sm:justify-end sm:px-7"><button type="button" class="btn-secondary" @click="close()">Cancelar</button><button class="btn-primary" x-text="mode==='edit'?'Salvar alterações':'Salvar usuário'"></button></div></form></div></div>
    </div>
    <script>function userManager(c){const empty=()=>({id:'',name:'',email:'',phone:'',role:'member',active:'1',birth_date:'',address:'',avatar_url:null,has_avatar:false,self:false,action:c.storeUrl});return{modal:false,mode:'create',form:empty(),preview:null,removed:false,init(){if(c.initialMode==='edit'&&c.initialUser)this.openEdit(c.initialUser);else if(c.initialMode==='create'){this.mode='create';this.form={...empty(),...(c.initialUser||{})};this.preview=this.form.avatar_url;this.show()}},openCreate(){this.mode='create';this.form=empty();this.preview=null;this.removed=false;this.show()},openEdit(x){this.mode='edit';this.form={...empty(),...x,active:String(x.active)};this.preview=x.avatar_url;this.removed=false;this.show()},initials(){return(this.form.name||'?').split(' ').filter(Boolean).slice(0,2).map(x=>x[0]).join('').toUpperCase()},chooseImage(e){const f=e.target.files[0];if(f){this.preview=URL.createObjectURL(f);this.removed=false}},show(){this.modal=true;document.body.classList.add('overflow-hidden');this.$nextTick(()=>this.$refs.nameInput?.focus())},close(){this.modal=false;document.body.classList.remove('overflow-hidden')}}}</script>
</x-layouts.app>
